#include <stdio.h>
#include <stdlib.h>
#define MOD 99991
#define MAXN 50000
long long fib[MAXN + 1];
void calculateFibonacci() {
    fib[1] = 1;
    fib[2] = 1;
    for (int i = 3; i <= MAXN; i++) {
        fib[i] = (fib[i - 1] + fib[i - 2]) % MOD;
    }
}
long long calculateSubsetSum(int* arr, int n, int k) {
    long long sum = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        long long subsetSum = 0;
        int count = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                subsetSum += arr[i];
                count++;
            }
        }
        if (count == k) {
            sum = (sum + fib[count]) % MOD;
        }
    }
    return sum;
}
int main() {
    int t = 1;
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int* arr = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        calculateFibonacci();
        long long result = calculateSubsetSum(arr, n, k);
        printf("%lld\n", result);
        free(arr);
    }
    return 0;
}

