import java.util.Scanner;
public class Main {
    static final int MOD = 99991;
    static final int MAXN = 50000;
    static long[] fib = new long[MAXN + 1];
    public static void calculateFibonacci() {
        fib[1] = 1;
        fib[2] = 1;
        for (int i = 3; i <= MAXN; i++) {
            fib[i] = (fib[i - 1] + fib[i - 2]) % MOD;
        }
    }
    public static long calculateSubsetSum(int[] arr, int n, int k) {
        long sum = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            long subsetSum = 0;
            int count = 0;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    subsetSum += arr[i];
                    count++;
                }
            }
            if (count == k) {
                sum = (sum + fib[count]) % MOD;
            }
        }
        return sum;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = 1;
        while (t-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt();
            }
            calculateFibonacci();
            long result = calculateSubsetSum(arr, n, k);
            System.out.println(result);
        }
    }
}

